const intent = $json.intent || '';
const params = $json.intentParams || {};
const GOOGLE_API_KEY = $env.GOOGLE_API_KEY || '';

if (!GOOGLE_API_KEY) {
  return [{ json: { ...$json, responseText: '⚠️ GOOGLE_API_KEY not configured.', success: false } }];
}

let endpoint, body;
if (intent === 'translate') {
  endpoint = 'https://translation.googleapis.com/language/translate/v2';
  body = { q: params.text || $json.inputText || '', target: params.target_language || 'en', source: params.source_language || '', format: 'text' };
} else if (intent === 'detect_language') {
  endpoint = 'https://translation.googleapis.com/language/translate/v2/detect';
  body = { q: params.text || $json.inputText || '' };
} else {
  return [{ json: { ...$json, responseText: '❓ Unknown translate intent: ' + intent, success: false } }];
}

return [{ json: { ...$json, apiEndpoint: endpoint, apiBody: body } }];

const translations = $json.data?.translations;
if (!translations || translations.length === 0) {
  return [{ json: { ...$input.item.json, responseText: '🔄 No translation result.', success: true } }];
}
const t = translations[0];
const sourceLang = t.detectedSourceLanguage || $json.apiBody?.source || 'auto';
const translated = t.translatedText;
const original = $json.apiBody?.q || '';
const text = `🔄 Translation (${sourceLang} → ${$json.apiBody?.target || 'en'}):

${translated}`;
return [{ json: { ...$input.item.json, responseText: text, success: true } }];
